drh added on 2013-08-28 14:29:23:
The following query returns zero rows in version 3.8.0.  The correct answer
(returned by 3.7.17 and by PostgreSQL) is a single row:  1|NULL|1
CREATE TABLE t (id INTEGER PRIMARY KEY NOT NULL);
INSERT INTO t VALUES (1);
SELECT *
  FROM t AS t1
       LEFT OUTER JOIN t AS t2 ON t2.id BETWEEN 10 AND 20
       JOIN t AS t3 ON (t3.id = t1.id OR
                        t2.id IS NOT NULL AND t3.id = t2.id);
